ucs.sentinel_kql:
// Silk Typhoon / HAFNIUM — same detection on Sentinel SecurityEvent 4688.
// Requires GPO "Include command line in process creation events" so CommandLine is populated.
let _exchange_app_pools = dynamic(["MSExchangeOWAAppPool","MSExchangeECPAppPool","MSExchangeServicesAppPool","MSExchangeAutodiscoverAppPool","MSExchangeMapiFrontEndAppPool","MSExchangeRpcProxyFrontEndAppPool","MSExchangePowerShellAppPool","MSExchangePowerShellFrontEndAppPool"]);
let _suspicious_children = dynamic(["\\cmd.exe","\\powershell.exe","\\pwsh.exe","\\powershell_ise.exe","\\net.exe","\\net1.exe","\\whoami.exe","\\nltest.exe","\\systeminfo.exe","\\ipconfig.exe","\\quser.exe","\\tasklist.exe","\\reg.exe","\\cscript.exe","\\wscript.exe","\\certutil.exe","\\bitsadmin.exe","\\procdump.exe","\\procdump64.exe","\\rundll32.exe","\\7z.exe","\\7za.exe"]);
SecurityEvent
| where TimeGenerated > ago(7d)
| where EventID == 4688
| where ParentProcessName endswith "\\w3wp.exe"
| where CommandLine has_any (_exchange_app_pools) or ParentProcessName has_any (_exchange_app_pools)
| where NewProcessName has_any (_suspicious_children)
| where Account !endswith "$"
| project TimeGenerated, Computer, Account, ParentProcessName, NewProcessName, CommandLine, TokenElevationType
| order by TimeGenerated desc
